#!/bin/sh
set -eu

script_dir="$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)"
repo_dir="$(cd "$script_dir/.." && pwd)"
hooks_json="$repo_dir/config/hooks.json"
offsets_dir="$repo_dir/symbol-offsets"
out_header="$repo_dir/src/hook_config.h"

if [ ! -f "$hooks_json" ]; then
    echo "ERROR: hooks.json not found at $hooks_json" >&2
    exit 1
fi

echo "Generating hook_config.h..."
echo "  hooks.json : $hooks_json"
echo "  offsets dir: $offsets_dir"

cat > "$out_header" <<'HEADER'
// Auto-generated by gen_hook_config.sh from config/hooks.json
// DO NOT EDIT MANUALLY
//
// 每个 file 条目 = 一个 Collector 实例 = 一组嵌入的 BPF 字节码 + 一个 ringbuf map

#pragma once

#include <stddef.h>
#include <stdbool.h>

// ── Hook 运行时配置 ───────────────────────────────────────────────────

struct hook_cfg {
    const char *name;          // hook 名称，也是 SEC 程序名
    const char *target_path;   // 目标机器上的库路径
    size_t     offset;         // 文件偏移量（用于 uprobe 挂载）
    bool       retprobe;       // true = uretprobe
};

// ── 文件分组（一个分组 = 一个 Collector 实例）──────────────────────────

struct file_group {
    const char *name;          // 逻辑标识，如 "routing"
    const void *embed_data;    // 指向嵌入的 BPF 字节码数组
    unsigned int embed_size;   // 字节码数组长度（和 xxd -i 生成的 _len 类型一致）
    const char *ringbuf_map;   // ringbuf map 名称
    int         module_id;     // 模块 ID（对应 vsomeip_event.module_id）
    int         hook_count;    // 本组的 hook 数量
    const struct hook_cfg *hooks;   // 指向本组的 hook 配置数组
    const char **hook_names;        // 指向本组的 hook 名数组
};

HEADER

python3 - "$hooks_json" "$offsets_dir" >> "$out_header" <<'PYTHON'
import json
import sys
import os

hooks_file = sys.argv[1]
offsets_dir = sys.argv[2]

with open(hooks_file) as f:
    config = json.load(f)

files = config["files"]

# ── 第一步：查偏移，生成 hook 配置数组 ────────────────────────────────
offset_cache = {}

def load_offsets(lib):
    if lib in offset_cache:
        return offset_cache[lib]
    offset_file = os.path.join(offsets_dir, f"{lib}.offsets.demangled.tsv")
    if not os.path.exists(offset_file):
        print(f"// ERROR: offset file not found: {offset_file}", file=sys.stderr)
        sys.exit(1)
    lookup = {}
    with open(offset_file) as f:
        f.readline()
        for line in f:
            cols = line.rstrip('\n').split('\t')
            if len(cols) >= 7:
                lookup[cols[6]] = cols[0]
    offset_cache[lib] = lookup
    return lookup

# ── 第二步：嵌入数据的外部声明 ─────────────────────────────────────────
# 实际定义在 src/bpf/embed_data.cpp 中（由 Makefile 自动生成），
# 那里 #include 所有 embed 头文件，确保只编译一次。

print("")
print("// ── 嵌入的 BPF 字节码（extern，实际定义在 bpf/embed_data.cpp）─────")
for fg in files:
    name = fg["name"]
    print(f"extern unsigned char {name}_bpf_o[];")
    print(f"extern unsigned int  {name}_bpf_o_len;")
print("")

# ── 第三步：按分组生成 hook_cfg 数组 ───────────────────────────────────
total_hooks = 0
group_info = []  # (fg, arr_name, names_arr, hcount)

for fg in files:
    name = fg["name"]
    lib = fg["lib"]
    target_path = fg["target_path"]
    lookup = load_offsets(lib)

    arr_name = f"hook_cfgs_{name}"
    names_arr = f"hook_names_{name}"

    print(f"// {name}.bpf.o 的 hook 配置（{len(fg['hooks'])} 个）")
    print(f"static const struct hook_cfg {arr_name}[] = {{")
    for h in fg["hooks"]:
        offset = lookup.get(h["demangled"])
        if offset is None:
            print(f'    // WARNING: symbol not found: {h["name"]}', file=sys.stderr)
            continue
        rp = 1 if h.get("retprobe", False) else 0
        print(f'    {{"{h["name"]}", "{target_path}", (size_t){offset}, {rp}}},')
    print("};")
    print(f"static const char* {names_arr}[] = {{")
    for h in fg["hooks"]:
        print(f'    "{h["name"]}",')
    print("};")
    print("")

    group_info.append((fg, arr_name, names_arr, len(fg["hooks"])))
    total_hooks += len(fg["hooks"])

# ── 第四步：生成 file_groups[] 汇总表 ─────────────────────────────────
print("// 文件分组表（一个分组 = 一个 Collector 实例）")
print("static const struct file_group file_groups[] = {")
for fg, arr_name, names_arr, hcount in group_info:
    name = fg["name"]
    print(f'    {{"{name}", {name}_bpf_o, {name}_bpf_o_len, '
          f'"{fg["ringbuf_map"]}", {fg["module_id"]}, '
          f'{hcount}, {arr_name}, {names_arr}}},')
print("};")
print(f"#define NUM_FILE_GROUPS {len(files)}")
print(f"#define TOTAL_HOOKS {total_hooks}")
print("")
print(f"// Generated: {total_hooks} hooks, {len(files)} file groups")
PYTHON

echo ""
echo "Generated: $out_header"
echo "Done."
